      { cat: "terap", type: "pg", q: "Manakah praktik yang paling sesuai dengan Amsal 4?", opts: ["Membiarkan semua pengaruh masuk", "Menutupi dosa sendirian", "Menilai hanya penampilan luar", "Menguji kebiasaan dan mengarahkan langkah pada kebenaran"], answer: 3, explain: "Pasal ini menghubungkan penjagaan batin dengan mulut, mata, dan langkah yang terarah." },
      { cat: "mengisi", type: "pg", q: "Lengkapi perintah pasal ini: tempuhlah jalan yang rata dan jangan menyimpang ke kanan atau ke ...", opts: ["depan", "kiri", "atas", "belakang"], answer: 1, explain: "Amsal 4:27 meminta pembaca tidak menyimpang ke kanan atau ke kiri." }
